const main = require('../../lib/jibo-emotion-system');

let EmotionSystem = main.emotionSystem.EmotionSystem;
let EmotionName = main.common.EmotionName;
let ImpactSize = main.common.ImpactSize;
let EmotionPoint = main.common.EmotionPoint;
let SensorySystem = main.sensing.SensorySystem;
let ImpactValues = main.emotion.ImpactValues;
let JIBO_BASELINE = main.emotion.JIBO_BASELINE;
const jibo = require('../../../jibo');

const DELTA = 0.001;

let FileUtils  = require('jibo-cai-utils').FileUtils;

describe('EmotionSystem', () => {
    let es;
    let clock;

    before(() => {
        clock = sinon.useFakeTimers();
    });

    beforeEach((done) => {
        es = new EmotionSystem();
        es.init({
            jibo: jibo
        }).then(done);
    });

    afterEach(() => {
        es.dispose();
    });


    after(() => {
        clock.restore();
    });

    it('Should export main modules', () => {
        let mainExport  = FileUtils.getProjectMainExport(module);
        expect(mainExport.emotionSystem.EmotionSystem).to.equal(EmotionSystem);
        expect(mainExport.sensing.SensorySystem).to.equal(SensorySystem);
    });

    it('should initialize emotion system cleanly', (done) => {
        let emotionSystem = new EmotionSystem();
        emotionSystem.init({
            jibo: jibo
        }).then(() => {
            expect(emotionSystem).to.have.property('events');
            done();
        }).catch(done);
        emotionSystem.dispose();
    });

    it('should dispose cleanly', () => {
        let emotionSystem = new EmotionSystem();
        emotionSystem.init({
            jibo: jibo
        }).then(() => {
            emotionSystem.dispose();
            expect(emotionSystem.rules).to.be.empty;
            expect(emotionSystem.sensors).to.be.empty;
        }).catch();
    });

    it('Should initialize to neutral emotional state', () => {
        let emotion = es.getNearestEmotion();
        expect(emotion.name).to.equal(EmotionName.NEUTRAL);
    });

    it('Should initialize position to 0,0', () => {
        let emotionalState = es.getCurrentEmotionalValues();
        expect(emotionalState.valence).to.equal(JIBO_BASELINE.emotionValues.valence);
        expect(emotionalState.confidence).to.equal(JIBO_BASELINE.emotionValues.confidence);
    });

    it('Should impact emotional state', function(done) {
        const impact = new EmotionPoint(
            ImpactValues.get(ImpactSize.HIGH_POS),
            ImpactValues.get(ImpactSize.HIGH_POS)
        )
        sinon.stub(jibo.action, 'getState', () => {
            return {
                sleep: 'AWAKE',
                time: new Date()
            };
        });
        sinon.stub(jibo.action, 'addPlayAnimationGoal', function(data) {
            jibo.action.addPlayAnimationGoal.restore()
            jibo.action.getState.restore()
            expect(data.category).to.equal('laughing');
            let emotionalState = es.getCurrentEmotionalValues();
            let nearestEmotion = es.getNearestEmotion();
            expect(emotionalState.valence).to.be.closeTo(2.45, DELTA);
            expect(emotionalState.confidence).to.be.closeTo(2.2, DELTA);
            expect(nearestEmotion.name).to.equal(EmotionName.JOYFUL);
            done();
        });
        es.triggerImpact(impact);
    });

    it('Should reset to neutral state', () => {
        es._emotionSpace._resetToNeutral();
        let emotionalState = es.getCurrentEmotionalValues();
        let nearestEmotion = es.getNearestEmotion();
        expect(emotionalState.valence).to.be.closeTo(0.45, DELTA);
        expect(emotionalState.confidence).to.be.closeTo(0.2, DELTA);
        expect(nearestEmotion.name).to.equal(EmotionName.NEUTRAL);
    });

    it('Should allow multiple different impacts', () => {
        sinon.stub(jibo.action, 'addPlayAnimationGoal', (/*data*/) => {
        });
        es._emotionSpace._resetToNeutral();
        let impact = new EmotionPoint(
            ImpactValues.get(ImpactSize.MEDIUM_NEG),
            ImpactValues.get(ImpactSize.LOW_POS)
        )
        es.triggerImpact(impact);
        let emotionalState = es.getCurrentEmotionalValues();
        let nearestEmotion = es.getNearestEmotion();
        expect(emotionalState.valence).to.be.closeTo(-0.55, DELTA);
        expect(emotionalState.confidence).to.be.closeTo(0.7, DELTA);
        expect(nearestEmotion.name).to.equal(EmotionName.PESSIMISTIC);
        impact = new EmotionPoint(
            ImpactValues.get(ImpactSize.HIGH_POS),
            ImpactValues.get(ImpactSize.MEDIUM_NEG)
        )
        es.triggerImpact(impact);
        emotionalState = es.getCurrentEmotionalValues();
        nearestEmotion = es.getNearestEmotion();
        expect(emotionalState.valence).to.be.closeTo(1.45, DELTA);
        expect(emotionalState.confidence).to.be.closeTo(-0.3, DELTA);
        expect(nearestEmotion.name).to.equal(EmotionName.PLEASED);

        jibo.action.addPlayAnimationGoal.restore();
        sinon.restore(jibo.action.addPlayAnimationGoal);
    });
});
